//! D.PEEL.CELL.1 — Inner peel on the cell manifold.
//!
//! Operates on the flat grid (rows × cols dimensions).
//! Constrained by T_value (from outer peel) and T_spatial (from middle peel).
//! The value map and spatial map are already known — this peel assembles
//! the exact output by applying both transformations.
//!
//! Scoring: L1 cell distance — the arithmetic finisher.
//! The innermost shell of the nested peel architecture.

use super::super::vocabulary::*;

/// Result of the cell-level peel.
#[derive(Debug, Clone)]
pub struct CellPeelResult {
    /// The derived output grid.
    pub derived_output: Option<Vec<i64>>,
    /// L1 residual — sum of |derived - target| across all cells.
    pub l1_residual: u64,
    /// Total thoughts evaluated across all three peels.
    pub total_thoughts_evaluated: u32,
    /// Composition depth (0 = single thought, 1+ = composed).
    pub composition_depth: usize,
    /// Whether full understanding was achieved (L1 = 0 on all training pairs).
    pub understood: bool,
}

/// Peel the cell manifold: assemble the exact grid using value and spatial constraints.
///
/// The outer peel found which color maps to which (T_value).
/// The middle peel found which object moves where (T_spatial, encoded as
/// transformed_pairs where the spatial thought has already been applied).
///
/// This inner peel applies the value map to the spatially transformed grid
/// and measures the remaining L1 residual. If L1 = 0, understanding is achieved.
/// If L1 > 0, it searches the cell vocabulary (TilePattern, AdjacencyFill, etc.)
/// for refinements.
///
/// The cell peel is cheap because the search space is constrained —
/// value and spatial structure are already resolved.
pub fn peel_cell_manifold(
    transformed_pairs: &[(Vec<i64>, Vec<i64>)],
    transformed_test: Option<&[i64]>,
    rows: usize,
    cols: usize,
    value_map: &[(i64, i64)],
    value_thoughts_evaluated: u32,
    object_thoughts_evaluated: u32,
) -> CellPeelResult {
    let _n = transformed_pairs[0].0.len().min(transformed_pairs[0].1.len());

    // Apply value map to the spatially transformed grid
    let apply_value_map = |grid: &[i64]| -> Vec<i64> {
        grid.iter().map(|&v| {
            value_map.iter()
                .find(|(src, _)| *src == v)
                .map(|(_, tgt)| *tgt)
                .unwrap_or(v)
        }).collect()
    };

    let mapped_pairs: Vec<(Vec<i64>, Vec<i64>)> = transformed_pairs.iter()
        .map(|(inp, out)| (apply_value_map(inp), out.clone()))
        .collect();

    let mapped_test = transformed_test.map(|t| apply_value_map(t));

    // Measure L1 after value+spatial application
    let measure_l1 = |pairs: &[(Vec<i64>, Vec<i64>)]| -> u64 {
        pairs.iter().map(|(inp, out)| {
            inp.iter().zip(out.iter())
                .map(|(p, o)| (p - o).unsigned_abs())
                .sum::<u64>()
        }).sum()
    };

    let base_l1 = measure_l1(&mapped_pairs);

    // If value + spatial already achieves understanding, return immediately
    let understood = base_l1 == 0;

    let mut best = CellPeelResult {
        derived_output: mapped_test.clone(),
        l1_residual: base_l1,
        total_thoughts_evaluated: value_thoughts_evaluated + object_thoughts_evaluated,
        composition_depth: 0,
        understood,
    };

    // If not understood, search cell vocabulary for refinements
    let vocab = cell_vocabulary();
    let mut current_pairs = mapped_pairs;
    let mut current_test = mapped_test;

    // Peel up to 5 layers of cell-level refinement
    for _depth in 0..5 {
        let mut improved = false;

        for thought in &vocab {
            let new_pairs: Vec<(Vec<i64>, Vec<i64>)> = current_pairs.iter()
                .map(|(inp, out)| (thought.apply_to_values(inp, rows, cols), out.clone()))
                .collect();

            let l1 = measure_l1(&new_pairs);
            best.total_thoughts_evaluated += 1;

            // C(T) selects — lower L1 wins
            (l1 < best.l1_residual).then(|| {
                best.l1_residual = l1;
                best.composition_depth += 1;
                best.understood = l1 == 0;
                let new_test = current_test.as_ref()
                    .map(|t| thought.apply_to_values(t, rows, cols));
                best.derived_output = new_test.clone();
                current_pairs = new_pairs.clone();
                current_test = new_test;
                improved = true;
            });
        }

        // Manifold exhausted at this vocabulary — deeper peeling adds noise
        if !improved || best.understood { break; }
    }

    best
}
